import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.cg7huoEH.js";const u=JSON.parse('{"title":"Contributing to djsuperadmin","description":"","frontmatter":{},"headers":[],"relativePath":"Contribute/index.md","filePath":"Contribute/index.md"}'),i={name:"Contribute/index.md"};function o(r,e,d,l,h,c){return a(),n("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /djsuperadmin/Contribute.md for this page in Markdown format</div><h1 id="contributing-to-djsuperadmin" tabindex="-1">Contributing to djsuperadmin <a class="header-anchor" href="#contributing-to-djsuperadmin" aria-label="Permalink to &quot;Contributing to djsuperadmin&quot;">​</a></h1><p>First off, thanks for taking the time to contribute! 🎉</p><p><strong>djsuperadmin</strong> is a tiny Django app (no runtime dependencies except Django) that lets superusers edit page contents inline in the browser. It&#39;s MIT licensed and maintained by <a href="https://github.com/bnznamco" target="_blank" rel="noreferrer">bnznamco</a>. Every contribution helps — bug reports, docs fixes, and code all count.</p><p>This guide explains how to report issues, set up a development environment, and get your changes merged.</p><h2 id="reporting-bugs" tabindex="-1">Reporting bugs <a class="header-anchor" href="#reporting-bugs" aria-label="Permalink to &quot;Reporting bugs&quot;">​</a></h2><p>Found something broken? Please open an issue on the <a href="https://github.com/bnznamco/djsuperadmin/issues" target="_blank" rel="noreferrer">issue tracker</a>.</p><p>A good bug report includes:</p><ul><li>Your Django and Python versions (djsuperadmin is tested from Django 2.2 to 6.0 on Python 3.6+).</li><li>The template tags you&#39;re using and a minimal snippet that reproduces the problem.</li><li>What you expected to happen vs. what actually happened, plus any traceback.</li></ul><p>Before opening a new issue, take a quick look through the existing ones — someone may have already reported it.</p><h2 id="suggesting-enhancements" tabindex="-1">Suggesting enhancements <a class="header-anchor" href="#suggesting-enhancements" aria-label="Permalink to &quot;Suggesting enhancements&quot;">​</a></h2><p>Enhancement ideas are welcome on the same <a href="https://github.com/bnznamco/djsuperadmin/issues" target="_blank" rel="noreferrer">issue tracker</a>. Describe the use case you&#39;re trying to solve and, if you can, sketch how the API might look. Keep in mind that a core goal of this project is to stay small and dependency-free, so we tend to favour focused, minimal additions.</p><h2 id="your-first-code-contribution" tabindex="-1">Your first code contribution <a class="header-anchor" href="#your-first-code-contribution" aria-label="Permalink to &quot;Your first code contribution&quot;">​</a></h2><p>Unsure where to begin? Issues labelled <code>good first issue</code> or <code>help wanted</code> are a great place to start. In general the flow is:</p><ol><li>Fork the repository and clone your fork.</li><li>Set up your environment (see below) and run the tests to confirm everything works.</li><li>Create a branch, make your change, add or update tests, and open a pull request.</li></ol><h2 id="development-setup" tabindex="-1">Development setup <a class="header-anchor" href="#development-setup" aria-label="Permalink to &quot;Development setup&quot;">​</a></h2><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ul><li><strong>Python</strong> with <a href="https://docs.astral.sh/uv/" target="_blank" rel="noreferrer">uv</a> — manages the virtualenv and Python dependencies.</li><li><strong>Node</strong> with <a href="https://pnpm.io/" target="_blank" rel="noreferrer">pnpm</a> — builds the JS bundle and the docs.</li></ul><h3 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h3><p>Clone the repo and install everything with one command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><p>This runs <code>uv sync --dev</code> (Python deps + dev tools into a managed virtualenv) and <code>pnpm install</code> (JS toolchain for the Vite bundle and VitePress docs).</p><h3 id="chore-commands" tabindex="-1">Chore commands <a class="header-anchor" href="#chore-commands" aria-label="Permalink to &quot;Chore commands&quot;">​</a></h3><p>All common tasks are wrapped in the <code>Makefile</code>:</p><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>make install</code></td><td><code>uv sync --dev &amp;&amp; pnpm install</code> — set up Python + JS deps</td></tr><tr><td><code>make test</code></td><td>Run <code>flake8</code> on <code>djsuperadmin</code>, then <code>pytest</code> with coverage</td></tr><tr><td><code>make format</code></td><td>Format the codebase with <code>black</code></td></tr><tr><td><code>make lint</code></td><td>Lint <code>djsuperadmin</code> with <code>flake8</code></td></tr><tr><td><code>make build</code></td><td><code>pnpm run build</code> — rebuild <code>djsuperadmin/dist/djsuperadmin.bundle.js</code> with Vite</td></tr><tr><td><code>make migrations</code></td><td><code>uv run python manage.py makemigrations</code></td></tr><tr><td><code>make docs-dev</code></td><td>Serve the VitePress docs locally with hot reload</td></tr><tr><td><code>make docs-build</code></td><td>Build the static docs site</td></tr><tr><td><code>make docs-preview</code></td><td>Preview the built docs site</td></tr></tbody></table><p>Tests live in <code>tests/</code> (pytest + pytest-django). The example/demo project lives in <code>example/</code>.</p><h3 id="running-the-demo-app" tabindex="-1">Running the demo app <a class="header-anchor" href="#running-the-demo-app" aria-label="Permalink to &quot;Running the demo app&quot;">​</a></h3><p>The example project doubles as the test project (settings module <code>example.djsuperadmin_example.settings</code>). To run it locally:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> manage.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> manage.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> createsuperuser</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> manage.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> runserver</span></span></code></pre></div><p>Then log in at <code>/admin/</code> and open <code>/</code> — as a superuser you&#39;ll see the editable content regions inline on the page.</p><h3 id="rebuilding-the-js-bundle" tabindex="-1">Rebuilding the JS bundle <a class="header-anchor" href="#rebuilding-the-js-bundle" aria-label="Permalink to &quot;Rebuilding the JS bundle&quot;">​</a></h3><p>djsuperadmin ships a small JS bundle (built with <a href="https://vitejs.dev/" target="_blank" rel="noreferrer">Vite</a>) that is injected into the page by the <code>{% djsuperadminjs %}</code> tag; it lazy-loads SunEditor from a CDN for the WYSIWYG editor. If you change anything under the frontend sources, rebuild the bundle:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>This regenerates <code>djsuperadmin/dist/djsuperadmin.bundle.js</code>. Commit the rebuilt bundle alongside your source changes.</p><h2 id="coding-conventions" tabindex="-1">Coding conventions <a class="header-anchor" href="#coding-conventions" aria-label="Permalink to &quot;Coding conventions&quot;">​</a></h2><ul><li><strong>Formatting:</strong> we use <a href="https://black.readthedocs.io/" target="_blank" rel="noreferrer">black</a>. Run <code>make format</code> before committing.</li><li><strong>Linting:</strong> code must pass <a href="https://flake8.pycqa.org/" target="_blank" rel="noreferrer">flake8</a> — run <code>make lint</code> (also part of <code>make test</code>).</li><li>Keep the project dependency-free: don&#39;t add runtime dependencies beyond Django.</li><li>Add or update tests for any behaviour change, and make sure <code>make test</code> is green.</li></ul><h2 id="commit-conventions" tabindex="-1">Commit conventions <a class="header-anchor" href="#commit-conventions" aria-label="Permalink to &quot;Commit conventions&quot;">​</a></h2><p>We follow <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a>. This is not just for tidiness — releases are automated with <a href="https://python-semantic-release.readthedocs.io/" target="_blank" rel="noreferrer">python-semantic-release</a>, which derives the next version number and changelog directly from your commit messages.</p><p>Use messages like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat: add in-place editing for raw contents</span></span>
<span class="line"><span>fix: correct html replacement in nested elements</span></span>
<span class="line"><span>docs: document the superadmin_raw_content tag</span></span>
<span class="line"><span>chore: bump dev dependencies</span></span></code></pre></div><p>Rough guide to what each type triggers:</p><ul><li><code>fix:</code> → patch release</li><li><code>feat:</code> → minor release</li><li>a <code>BREAKING CHANGE:</code> footer (or <code>!</code> after the type) → major release</li><li><code>docs:</code>, <code>chore:</code>, <code>test:</code>, <code>refactor:</code>, etc. → no release on their own</li></ul><h2 id="pull-request-process" tabindex="-1">Pull request process <a class="header-anchor" href="#pull-request-process" aria-label="Permalink to &quot;Pull request process&quot;">​</a></h2><ol><li>Branch off <code>master</code> and keep your changes focused.</li><li>Run <code>make format</code> and <code>make test</code> locally — both should pass.</li><li>If you touched the frontend, run <code>make build</code> and commit the updated bundle.</li><li>Write clear, <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a>-style commit messages.</li><li>Open a pull request against <code>bnznamco/djsuperadmin</code>, describing the change and linking any related issue.</li></ol><p>A maintainer will review your PR, and CI will run the test suite. Once it&#39;s approved and green, it will be merged.</p><h2 id="release-flow" tabindex="-1">Release flow <a class="header-anchor" href="#release-flow" aria-label="Permalink to &quot;Release flow&quot;">​</a></h2><p>Releases are cut by maintainers, not on every merge. When it&#39;s time, the manual <strong>Release</strong> GitHub Actions workflow (<code>workflow_dispatch</code>) runs python-semantic-release: it reads the Conventional Commits since the last tag, determines the new version, updates the changelog, builds the package with <code>uv</code>, and publishes it to <a href="https://pypi.org/project/djsuperadmin/" target="_blank" rel="noreferrer">PyPI</a>. Writing good commit messages is what makes this work — thank you for keeping them clean!</p>`,47)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
